namespace sv_aab058d5d67549a9ad3cb6f78ec25ede.Models;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; set; } = Guid.NewGuid();
    public required string Title { get; set; }
    public required string Message { get; set; }
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; } = DateTime.UtcNow;
}

using sv_aab058d5d67549a9ad3cb6f78ec25ede.Models;

namespace sv_aab058d5d67549a9ad3cb6f78ec25ede.Services;

/// <summary>
/// Scoped per circuit. Holds notification state and notifies all
/// subscribers when any mutation occurs.
/// </summary>
public class NotificationHub
{
    private readonly List<Notification> _notifications = [];
    private readonly object _lock = new();

    /// <summary>
    /// Components subscribe to this event. The handler receives no args;
    /// subscribers should re-read state and call StateHasChanged.
    /// </summary>
    public event Action? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get
        {
            lock (_lock)
            {
                return _notifications.ToList().AsReadOnly();
            }
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }

        NotifyStateChanged();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var notification = _notifications.FirstOrDefault(n => n.Id == id);
            if (notification is not null)
                notification.IsRead = true;
        }

        NotifyStateChanged();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }

        NotifyStateChanged();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }

        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

using sv_aab058d5d67549a9ad3cb6f78ec25ede.Models;

namespace sv_aab058d5d67549a9ad3cb6f78ec25ede.Services;

/// <summary>
/// Scoped per circuit. Adds a random notification every 15 seconds.
/// Started/stopped explicitly by the Dashboard page so it only runs
/// while that page is active.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private Timer? _timer;

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Disk Usage High", "Server disk usage exceeded 85%.", Severity.Warning),
        ("Deployment Succeeded", "v2.4.1 deployed to production.", Severity.Info),
        ("CPU Spike Detected", "CPU usage above 95% for 30 seconds.", Severity.Critical),
        ("New User Registered", "A new user signed up.", Severity.Info),
        ("SSL Certificate Expiring", "Certificate expires in 7 days.", Severity.Warning),
        ("Database Connection Lost", "Primary database is unreachable.", Severity.Critical),
        ("Backup Completed", "Nightly backup finished successfully.", Severity.Info),
        ("Memory Pressure", "Available memory below 512 MB.", Severity.Warning),
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        // Timer fires on a thread-pool thread — NotificationHub.OnChange
        // will be invoked from that thread; subscribers must marshal to UI.
        _timer ??= new Timer(_ =>
        {
            var template = Templates[Random.Shared.Next(Templates.Length)];
            _hub.AddNotification(template.Title, template.Message, template.Severity);
        }, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    public void Stop()
    {
        _timer?.Change(Timeout.Infinite, Timeout.Infinite);
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _timer = null;
    }
}

