using sv_aab058d5d67549a9ad3cb6f78ec25ede.Models;

namespace sv_aab058d5d67549a9ad3cb6f78ec25ede.Services;

/// <summary>
/// Scoped per circuit. Adds a random notification every 15 seconds.
/// Started/stopped explicitly by the Dashboard page so it only runs
/// while that page is active.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private Timer? _timer;

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Disk Usage High", "Server disk usage exceeded 85%.", Severity.Warning),
        ("Deployment Succeeded", "v2.4.1 deployed to production.", Severity.Info),
        ("CPU Spike Detected", "CPU usage above 95% for 30 seconds.", Severity.Critical),
        ("New User Registered", "A new user signed up.", Severity.Info),
        ("SSL Certificate Expiring", "Certificate expires in 7 days.", Severity.Warning),
        ("Database Connection Lost", "Primary database is unreachable.", Severity.Critical),
        ("Backup Completed", "Nightly backup finished successfully.", Severity.Info),
        ("Memory Pressure", "Available memory below 512 MB.", Severity.Warning),
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        // Timer fires on a thread-pool thread — NotificationHub.OnChange
        // will be invoked from that thread; subscribers must marshal to UI.
        _timer ??= new Timer(_ =>
        {
            var template = Templates[Random.Shared.Next(Templates.Length)];
            _hub.AddNotification(template.Title, template.Message, template.Severity);
        }, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    public void Stop()
    {
        _timer?.Change(Timeout.Infinite, Timeout.Infinite);
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _timer = null;
    }
}

