@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += HandleStateChanged;
    }

    // OnChange may fire from a timer thread — marshal to the UI synchronization context.
    private async void HandleStateChanged()
    {
        try
        {
            await InvokeAsync(() =>
            {
                _unreadCount = Hub.GetUnreadCount();
                StateHasChanged();
            });
        }
        catch (ObjectDisposedException)
        {
            // Circuit was torn down; safe to ignore.
        }
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleStateChanged;
    }
}

