            @foreach (var n in _unread)
            {
                <li class="list-group-item d-flex justify-content-between align-items-start">
                    <div class="me-auto">
                        <span class="badge @SeverityBadgeClass(n.Severity) me-1">@n.Severity</span>
                        @n.Title
                        <br /><small class="text-muted">@n.Message</small>
                    </div>
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => Dismiss(n.Id)">Dismiss</button>
                </li>
            }
        }
    </ul>
</div>

@code {
    private List<Notification> _unread = [];

    protected override void OnInitialized()
    {
        RefreshUnread();
        Hub.OnChange += HandleStateChanged;
    }

    private void RefreshUnread()
    {
        _unread = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private async void HandleStateChanged()
    {
        try
        {
            await InvokeAsync(() =>
            {
                RefreshUnread();
                StateHasChanged();
            });
        }
        catch (ObjectDisposedException) { }
    }

    private static string SeverityBadgeClass(Severity severity) => severity switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= HandleStateChanged;
    }
}

