@page "/dashboard"
@rendermode InteractiveServer
@using sv_aab058d5d67549a9ad3cb6f78ec25ede.Services
@implements IDisposable
@inject SimulatorService Simulator

<PageTitle>Dashboard</PageTitle>

<h2>Dashboard</h2>

<p class="text-muted">A random notification is generated every 15 seconds by the simulator.</p>

<div class="row">
    <div class="col-md-6">
        <NotificationSummaryPanel />
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        Simulator.Start();
    }

    public void Dispose()
    {
        Simulator.Stop();
    }
}

